SELECT entity_category, COUNT(entity_id) AS entity_count
FROM geospatial_entities
GROUP BY entity_category;

SELECT DISTINCT u.username
FROM entity_metadata em
INNER JOIN users u ON em.last_modified_by = u.user_id;

SELECT u.username, eal.entity_id
FROM entity_access_logs eal
INNER JOIN users u ON eal.user_id = u.user_id;

SELECT DISTINCT U.username
FROM users U
JOIN geospatial_entities GE ON U.user_id = GE.created_by;

SELECT COUNT(entity_id) AS entities_created_in_2023
FROM entity_metadata
WHERE creation_date >= '2023-01-01' AND creation_date < '2024-01-01';

SELECT entity_id, diameter 
FROM geospatial_entities
WHERE diameter = (SELECT MAX(diameter) FROM geospatial_entities);

SELECT entity_id, version
FROM geospatial_entities
ORDER BY version ASC;
